def range_summary(nums):
    if not nums:
        return ''

    sorted_nums = sorted(set(nums))
    result = []
    i = 0

    while i < len(sorted_nums):
        start = i
        while i + 1 < len(sorted_nums) and sorted_nums[i] + 1 == sorted_nums[i + 1]:
            i += 1
        if start == i:
            result.append(str(sorted_nums[start]))
        else:
            result.append(f"{sorted_nums[start]}-{sorted_nums[i]}")
        i += 1

    return ','.join(result)
